#include <stdio.h>
#include <string.h>

int main() {
    int R;
    scanf("%d", &R);
    while (R--) {
        int L;
        scanf("%d", &L);
        char report[L + 1];
        scanf("%s", report);
        int valid = 1;
        int seenH = 0;
        for (int i = 0; i < L; i++) {
            if (report[i] == 'H') {
                if (seenH) {
                    valid = 0;
                    break;
                }
                seenH = 1;
            } else if (report[i] == 'T') {
                if (!seenH) {
                    valid = 0;
                    break;
                }
                seenH = 0;
            }
        }
        if (seenH) {
            valid = 0;
        }
        if (valid) {
            printf("Valid\n");
        } else {
            printf("Invalid\n");
        }
    }
    return 0;
}

